solutions.javascript:
// Solution
function findDuplicates(arr) {
  let map = new Map();
  for (let num of arr) {
    map.set(num, (map.get(num) || 0) + 1);
  }
  let result = {};
  for (let [key, value] of map) {
    if (value > 1) {
      result[key] = value;
    }
  }
  return result;
}
